t.script:
                //
(function(){
'use strict';
var bell=document.getElementById('notifBell');
var dropdown=document.getElementById('notifDropdown');
bell.addEventListener('click',function(e){e.stopPropagation();dropdown.classList.toggle('open');});
document.addEventListener('click',function(){dropdown.classList.remove('open');});
dropdown.addEventListener('click',function(e){e.stopPropagation();});
document.getElementById('markAllRead').addEventListener('click',function(){
    fetch('/customer_support/dashboard/sla_alerts/mark_read',{method:'POST',credentials:'same-origin',headers:{'X-Requested-With':'XMLHttpRequest'}})
    .catch(function(){})
    .then(function(){loadSlaAlerts();});
});
document.querySelectorAll('.notif-nav-link').forEach(function(a){
    a.addEventListener('click',function(e){
        e.preventDefault();
        window.switchView(this.getAttribute('data-view'));
        dropdown.classList.remove('open');
    });
});
function loadSlaAlerts(){
    fetch('/customer_support/dashboard/sla_alerts',{method:'GET',credentials:'same-origin',headers:{'Accept':'application/json'}})
    .then(function(r){if(!r.ok)throw new Error(r.status);return r.json();})
    .then(function(data){renderAlerts(data.alerts||[]);})
    .catch(function(){renderAlerts([]);});
}
function renderAlerts(alerts){
    var list=document.getElementById('notifList');
    var badge=document.getElementById('notifBadge');
    if(!alerts.length){
        list.innerHTML='<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#10b981;display:block;margin-bottom:.5rem;"></i>All tickets are on track!</div>';
        badge.classList.add('d-none');
        return;
    }
    badge.textContent=alerts.length;
    badge.classList.remove('d-none');
    list.innerHTML=alerts.map(function(a){
        var isAssignment=a.alert_type==='assignment';
        var cls=isAssignment?'at-risk':(a.sla_status==='breached'?'breached':'at-risk');
        var icon=isAssignment?'bi-ticket-detailed-fill':(cls==='breached'?'bi-x-octagon-fill':'bi-exclamation-triangle-fill');
        var label=isAssignment?'New Assignment':(cls==='breached'?'SLA Breached':'At Risk');
        var policyLine=isAssignment?'Ticket assigned to you':'Policy: '+(a.policy_name||'None');
        return '<div class="notif-item unread">'
            +'<div class="notif-icon-wrap '+cls+'"><i class="bi '+icon+'"></i></div>'
            +'<div class="notif-body">'
            +'<div class="notif-title">Ticket #'+a.ticket_id+' \u2014 '+a.subject+'</div>'
            +'<div class="notif-sub">'+label+' \u00b7 '+a.time_display+'</div>'
            +'<div class="notif-time-text">Project: '+(a.project_name||'General')+'</div>'
            +'</div><div class="notif-dot '+cls+'"></div></div>';
    }).join('');
}
document.addEventListener('DOMContentLoaded',function(){loadSlaAlerts();setInterval(loadSlaAlerts,30000);});
})();
//

                //
(function(){
'use strict';
var INTERVAL=15000;
var A=[
    {key:'open_tickets',sel:'[data-key="open_tickets"] .stat-value'},
    {key:'total_tickets',sel:'[data-key="total_tickets"] .stat-value'},
    {key:'high_priority',sel:'[data-key="high_priority"] .stat-value'},
    {key:'urgent',sel:'[data-key="urgent"] .stat-value'},
    {key:'avg_open_hours',sel:'[data-key="avg_open_hours"] .stat-value'},
    {key:'total_hours',sel:'[data-key="total_hours"] .stat-value'},
    {key:'avg_high_hours',sel:'[data-key="avg_high_hours"] .stat-value'},
    {key:'avg_urgent_hours',sel:'[data-key="avg_urgent_hours"] .stat-value'},
    {key:'resolved_tickets',sel:'[data-key="resolved_tickets"] .stat-value'},
    {key:'solve_rate',sel:'[data-key="solve_rate"] .stat-value',sfx:'%'},
    {key:'high_resolved',sel:'[data-key="high_resolved"] .stat-value'},
    {key:'urgent_resolved',sel:'[data-key="urgent_resolved"] .stat-value'}
];
var P=[
    {key:'today_closed',sel:'[data-key="today_closed"] .performance-value'},
    {key:'avg_resolve_rate',sel:'[data-key="avg_resolve_rate"] .performance-value',sfx:'%'},
    {key:'daily_target',sel:'[data-key="daily_target"] .performance-value',sfx:'%'},
    {key:'achievement',sel:'[data-key="achievement"] .performance-value',sfx:'%'},
    {key:'sample_performance',sel:'[data-key="sample_performance"] .score-badge',sfx:'%'}
];
function upd(sel,val,sfx){var el=document.querySelector(sel);if(el)el.textContent=val+(sfx||'');}
function flash(sel){var el=document.querySelector(sel);if(el){el.style.transition='color 0.3s';el.style.color='#059669';setTimeout(function(){el.style.color='';},600);}}
function updBar(v){var b=document.querySelector('.progress-bar');if(b){b.style.width=v+'%';b.className='progress-bar '+(v>=80?'bg-success':'bg-warning');}}
function updBarLabel(v){var ls=document.querySelectorAll('.progress-label span');if(ls.length>=2)ls[1].textContent=v+'%';}
function updTime(){var t=new Date().toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});document.querySelectorAll('.last-updated').forEach(function(el){el.innerHTML='<i class="bi bi-clock me-1"></i>Updated at '+t;});}
function run(){
    fetch('/customer_support/dashboard/analytics',{method:'GET',credentials:'same-origin',headers:{'Accept':'application/json'}})
    .then(function(r){if(!r.ok)throw new Error(r.status);return r.json();})
    .then(function(d){
        var a=d.analytics||{},p=d.performance||{};
        A.forEach(function(i){var v=a[i.key];if(v!==undefined){upd(i.sel,v,i.sfx||'');flash(i.sel);}});
        P.forEach(function(i){var v=p[i.key];if(v!==undefined)upd(i.sel,v,i.sfx||'');});
        if(p.achievement!==undefined){updBar(p.achievement);updBarLabel(p.achievement);}
        updTime();
    })
    .catch(function(e){console.warn('Analytics refresh failed:',e);});
}
document.addEventListener('DOMContentLoaded',function(){run();setInterval(run,INTERVAL);});
})();
//

                //
document.addEventListener('DOMContentLoaded',function(){

    /* ── Spinner ── */
    var spinStyle=document.createElement('style');
    spinStyle.textContent='@keyframes spin{to{transform:rotate(360deg);}}';
    document.head.appendChild(spinStyle);

    /* ── Alerts auto-close ── */
    setTimeout(function(){document.querySelectorAll('.alert').forEach(function(a){new bootstrap.Alert(a).close();});},5000);

    /* ── Toast ── */
    var toastEl=document.getElementById('kanbanToast');
    var toastTimer;
    function showToast(msg,type){
        toastEl.textContent=msg;
        toastEl.className='show '+(type||'');
        clearTimeout(toastTimer);
        toastTimer=setTimeout(function(){toastEl.className='';},3000);
    }

    /* ── Page switching ── */
    window.switchView=function(viewId){
        document.querySelectorAll('.header-nav .nav-link').forEach(function(l){l.classList.remove('active');});
        var nl=document.querySelector('.header-nav .nav-link[data-view="'+viewId+'"]');
        if(nl)nl.classList.add('active');
        document.querySelectorAll('.mobile-nav-item').forEach(function(i){i.classList.remove('active');});
        var mni=document.querySelector('.mobile-nav-item[data-view="'+viewId+'"]');
        if(mni)mni.classList.add('active');
        document.querySelectorAll('.page-content').forEach(function(p){p.style.display='none';});
        var target=document.getElementById(viewId+'-page');
        if(target)target.style.display='block';
    };
    document.querySelectorAll('.header-nav .nav-link').forEach(function(link){
        link.addEventListener('click',function(e){e.preventDefault();window.switchView(this.getAttribute('data-view'));});
    });

    /* ── Handle ?view= param from external pages ── */
    (function(){
        var p = new URLSearchParams(window.location.search);
        var v = p.get('view');
        if(v && document.getElementById(v+'-page')) window.switchView(v);
    })();
    document.querySelectorAll('.action-card[data-view]').forEach(function(card){
        card.addEventListener('click',function(e){e.preventDefault();window.switchView(this.getAttribute('data-view'));});
    });

    /* ── List / Kanban toggle ── */
    var listViewBtn=document.getElementById('listViewBtn');
    var kanbanViewBtn=document.getElementById('kanbanViewBtn');
    var listView=document.getElementById('listView');
    var kanbanView=document.getElementById('kanbanView');
    var shouldShowKanbanReminder=true;

    function showList(){
        listView.style.display='block';kanbanView.style.display='none';
        listViewBtn.classList.add('active');kanbanViewBtn.classList.remove('active');
        document.getElementById('mobilePillList').classList.add('active');
        document.getElementById('mobilePillKanban').classList.remove('active');
        shouldShowKanbanReminder=true;
    }
    function showKanban(){
        listView.style.display='none';kanbanView.style.display='block';
        listViewBtn.classList.remove('active');kanbanViewBtn.classList.add('active');
        document.getElementById('mobilePillList').classList.remove('active');
        document.getElementById('mobilePillKanban').classList.add('active');
        updateCounts();
        if(shouldShowKanbanReminder){
            showToast('Please update ticket status promptly to keep customers assured.','warning');
            shouldShowKanbanReminder=false;
        }
    }
    listViewBtn.addEventListener('click',showList);
    kanbanViewBtn.addEventListener('click',showKanban);
    document.getElementById('mobilePillList').addEventListener('click',showList);
    document.getElementById('mobilePillKanban').addEventListener('click',showKanban);
    var kanbanToggleBtn=document.getElementById('kanbanToggleBtn');
    if(kanbanToggleBtn){
        kanbanToggleBtn.addEventListener('click',function(){
            window.switchView('tickets');showKanban();this.classList.toggle('active');
        });
    }

    /* ── Column counts ── */
    function updateCounts(){
        ['new','in_progress','resolved','closed'].forEach(function(s){
            var col=document.getElementById('col-'+s);
            var cnt=document.getElementById('count-'+s);
            if(col&&cnt)cnt.textContent=col.querySelectorAll('.kanban-card').length;
        });
    }

    /* ── Mobile kanban collapse ── */
    document.querySelectorAll('.kanban-col-header[data-col-toggle]').forEach(function(header){
        header.addEventListener('click',function(){
            if(window.innerWidth>768)return;
            var col=this.closest('.kanban-col');
            col.classList.toggle('collapsed');
            var chevron=this.querySelector('.kanban-col-chevron');
            if(chevron){chevron.classList.toggle('bi-chevron-down');chevron.classList.toggle('bi-chevron-up');}
        });
    });

    /* ── Filter state ── */
    var activeStatus='all';
    var activePriority='all';

    document.querySelectorAll('[data-filter-type="status"]').forEach(function(btn){
        btn.addEventListener('click',function(){
            document.querySelectorAll('[data-filter-type="status"]').forEach(function(b){b.classList.remove('active');});
            this.classList.add('active');
            activeStatus=this.getAttribute('data-filter-val');
            applyFilters();
        });
    });
    document.querySelectorAll('[data-filter-type="priority"]').forEach(function(btn){
        btn.addEventListener('click',function(){
            document.querySelectorAll('[data-filter-type="priority"]').forEach(function(b){b.classList.remove('active');});
            this.classList.add('active');
            activePriority=this.getAttribute('data-filter-val');
            applyFilters();
        });
    });

    /* ── Search ── */
    var searchInput=document.getElementById('ticketSearchInput');
    if(searchInput)searchInput.addEventListener('input',applyFilters);

    function applyFilters(){
        var term=searchInput?searchInput.value.toLowerCase():'';
        var rows=document.querySelectorAll('.ticket-row');
        var visible=0;
        rows.forEach(function(r){
            var rowState=r.getAttribute('data-state')||'';
            var rowPrio=r.getAttribute('data-priority')||'';
            var rowText=r.textContent.toLowerCase();
            var stateMatch=activeStatus==='all'||(activeStatus==='new'&&(rowState==='new'||rowState==='assigned'))||rowState===activeStatus;
            var prioMatch=activePriority==='all'||rowPrio===activePriority;
            var textMatch=!term||rowText.includes(term);
            var show=stateMatch&&prioMatch&&textMatch;
            r.style.display=show?'':'none';
            if(show)visible++;
        });
        /* Kanban search */
        document.querySelectorAll('.kanban-card').forEach(function(c){
            c.style.display=c.textContent.toLowerCase().includes(term)?'':'none';
        });
        /* Update count label */
        var countEl=document.getElementById('filterCount');
        if(countEl)countEl.textContent=visible+' ticket'+(visible!==1?'s':'');
        /* Show/hide empty state */
        var table=document.getElementById('ticketTable');
        var emptyState=document.getElementById('ticketsEmptyState');
        if(table&&table.style.display!=='none'){
            if(emptyState){
                if(visible===0&&rows.length>0){emptyState.style.display='block';}
                else{emptyState.style.display='none';}
            }
        }
    }

    /* ── Helpers ── */
    function escHtml(str){return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}

    function toColState(state){
        if(state==='assigned'||state==='new')return 'new';
        if(state==='in_progress')return 'in_progress';
        if(state==='resolved')return 'resolved';
        if(state==='closed')return 'closed';
        return 'new';
    }
    function stateLabel(state){
        var map={new:'New',assigned:'Assigned',in_progress:'In Progress',resolved:'Resolved',closed:'Closed'};
        return map[state]||state.replace(/_/g,' ').replace(/\b\w/g,function(c){return c.toUpperCase();});
    }
    function stateCssClass(state){
        if(state==='new'||state==='assigned')return 'status-new';
        if(state==='in_progress')return 'status-in-progress';
        if(state==='resolved')return 'status-resolved';
        if(state==='closed')return 'status-closed';
        return 'status-new';
    }
    function prioClass(p){return 'priority-'+(p||'low');}
    function prioLabel(p){return(p||'low').charAt(0).toUpperCase()+(p||'low').slice(1);}

    /* Age helper */
    function ticketAge(createDate){
        if(!createDate)return '';
        var d=new Date(createDate);
        if(isNaN(d))return createDate;
        var diffMs=Date.now()-d.getTime();
        var diffMins=Math.floor(diffMs/60000);
        if(diffMins<60)return diffMins+'m ago';
        var diffHrs=Math.floor(diffMins/60);
        if(diffHrs<24)return diffHrs+'h ago';
        return Math.floor(diffHrs/24)+'d ago';
    }

    /* Initials from name */
    function initials(name){
        if(!name)return '?';
        var parts=name.trim().split(' ');
        return(parts[0][0]+(parts.length>1?parts[parts.length-1][0]:'')).toUpperCase();
    }

    /* Avatar colours keyed by first char */
    var AVATAR_COLORS=['#065f46','#065f46','#185fa5','#0f6e56','#854f0b','#712b13','#534ab7','#3b6d11'];
    function avatarColor(name){
        var c=(name||'?').charCodeAt(0)%AVATAR_COLORS.length;
        return AVATAR_COLORS[c];
    }

    /* ── Build list row ── */
    function buildListRow(t){
        var sc=stateCssClass(t.state);
        var sd=stateLabel(t.state);
        var pc=prioClass(t.priority);
        var pl=prioLabel(t.priority);
        var prioAccent='tr-'+(t.priority||'low');
        var av=t.customer_id?'/web/image/res.partner/'+t.customer_id+'/avatar_128':'';
        var initStr=initials(t.customer_name);
        var bgColor=avatarColor(t.customer_name);

        /* Split date into date + time parts if possible */
        var dateParts=String(t.create_date||'').split(' ');
        var datePart=dateParts[0]||'';
        var timePart=dateParts[1]?dateParts[1].substring(0,5):'';

        var avatarHtml=av
            ?'<img class="cust-img" src="'+escHtml(av)+'" onerror="this.style.display=\'none\';this.nextSibling.style.display=\'flex\';" /><div class="cust-initials" style="display:none;background:'+bgColor+';">'+escHtml(initStr)+'</div>'
            :'<div class="cust-initials" style="background:'+bgColor+';">'+escHtml(initStr)+'</div>';

        return '<tr class="ticket-row '+prioAccent+'" data-ticket-id="'+t.id+'" data-state="'+escHtml(t.state)+'" data-priority="'+escHtml(t.priority||'low')+'"'
            +' data-subject="'+escHtml(t.subject||'')+'" data-customer="'+escHtml(t.customer_name||'')+'" data-date="'+escHtml(t.create_date||'')+'">'
            +'<td class="col-ticket"><div class="tkt-ref">'+escHtml(t.name)+'</div><div class="tkt-subject">'+escHtml(t.subject||'No description')+'</div></td>'
            +'<td class="col-customer"><div class="cust-cell">'+avatarHtml+'<span class="cust-name-text">'+escHtml(t.customer_name)+'</span></div></td>'
            +'<td class="col-status"><span class="table-status-badge '+sc+'">'+sd+'</span></td>'
            +'<td class="col-priority"><span class="table-priority-badge '+pc+'">'+pl+'</span></td>'
            +'<td class="col-created"><div class="created-date-main">'+escHtml(datePart)+'</div><div class="created-date-time">'+escHtml(timePart)+'</div></td>'
            +'<td class="col-project"><span class="project-tag"><i class="bi bi-folder2"></i> Support</span></td>'
            +'</tr>';
    }

    /* ── Build kanban card ── */
    function buildKanbanCard(t){
        var av=t.customer_id?'/web/image/res.partner/'+t.customer_id+'/avatar_128':'/web/static/img/avatar_gray.svg';
        var pc=prioClass(t.priority);
        var pl=prioLabel(t.priority);
        return '<div class="kanban-card" data-ticket-id="'+t.id+'" data-state="'+toColState(t.state)+'" draggable="true">'
            +'<div class="kanban-card-id">'+escHtml(t.name)+'</div>'
            +'<div class="kanban-card-subject">'+escHtml(t.subject||'')+'</div>'
            +'<div class="kanban-card-footer"><div class="kanban-card-customer"><img src="'+escHtml(av)+'" onerror="this.src=\'/web/static/img/avatar_gray.svg\'"/><span>'+escHtml(t.customer_name)+'</span></div>'
            +'<span class="kanban-priority '+pc+'">'+pl+'</span></div></div>';
    }

    /* ── Tooltip ── */
    var tooltip=document.getElementById('ticketTooltip');
    var tooltipTimer;

    function showTooltip(row,e){
        var subject=row.getAttribute('data-subject')||'';
        var customer=row.getAttribute('data-customer')||'';
        var state=row.getAttribute('data-state')||'';
        var priority=row.getAttribute('data-priority')||'';
        var date=row.getAttribute('data-date')||'';
        var ref=row.querySelector('.tkt-ref');
        var refTxt=ref?ref.textContent:'';
        tooltip.innerHTML=
            '<div class="tt-ref">'+escHtml(refTxt)+'</div>'
            +'<div class="tt-subject">'+escHtml(subject)+'</div>'
            +'<div class="tt-row"><span class="tt-key">Customer</span><span class="tt-val">'+escHtml(customer)+'</span></div>'
            +'<div class="tt-row"><span class="tt-key">Status</span><span class="tt-val">'+escHtml(stateLabel(state))+'</span></div>'
            +'<div class="tt-row"><span class="tt-key">Priority</span><span class="tt-val">'+escHtml(prioLabel(priority))+'</span></div>'
            +'<div class="tt-row"><span class="tt-key">Age</span><span class="tt-val">'+escHtml(ticketAge(date))+'</span></div>';

        var rect=row.getBoundingClientRect();
        var tipTop=rect.top+window.scrollY+(rect.height/2)-60;
        var tipLeft=rect.right+12;
        if(tipLeft+270>window.innerWidth)tipLeft=rect.left-282;
        tooltip.style.top=tipTop+'px';
        tooltip.style.left=tipLeft+'px';
        tooltip.classList.add('visible');
    }

    function hideTooltip(){tooltip.classList.remove('visible');}

    function bindRowEvents(){
        document.querySelectorAll('.ticket-row').forEach(function(row){
            row.addEventListener('click',function(){
                var id=this.getAttribute('data-ticket-id');
                if(id)window.location.href='/customer_support/ticket/'+id;
            });
            row.addEventListener('mouseenter',function(e){
                clearTimeout(tooltipTimer);
                var r=this;
                tooltipTimer=setTimeout(function(){showTooltip(r,e);},320);
            });
            row.addEventListener('mouseleave',function(){
                clearTimeout(tooltipTimer);
                hideTooltip();
            });
        });
    }

    /* ── Ticket polling ── */
    var _renderedIds={};
    var _firstLoad=true;

    function renderTickets(tickets){
        var newIds={};
        tickets.forEach(function(t){newIds[t.id]=true;});
        var addedIds=[];
        if(!_firstLoad){tickets.forEach(function(t){if(!_renderedIds[t.id])addedIds.push(t.id);});}
        _renderedIds=newIds;
        _firstLoad=false;

        var tbody=document.getElementById('ticketTableBody');
        var table=document.getElementById('ticketTable');
        var emptyState=document.getElementById('ticketsEmptyState');
        var loading=document.getElementById('ticketsLoadingState');
        loading.style.display='none';

        if(tickets.length===0){
            table.style.display='none';
            emptyState.style.display='block';
        } else {
            emptyState.style.display='none';
            table.style.display='';
            tbody.innerHTML=tickets.map(buildListRow).join('');
            bindRowEvents();
        }

        /* Kanban */
        var cols={new:[],in_progress:[],resolved:[],closed:[]};
        tickets.forEach(function(t){var s=toColState(t.state);if(cols[s])cols[s].push(t);});
        ['new','in_progress','resolved','closed'].forEach(function(state){
            var colEl=document.getElementById('col-'+state);
            if(!colEl)return;
            var existingIds={};
            colEl.querySelectorAll('.kanban-card').forEach(function(card){existingIds[card.getAttribute('data-ticket-id')]=card;});
            cols[state].forEach(function(t){
                var tid=String(t.id);
                if(!existingIds[tid]){
                    var tmp=document.createElement('div');
                    tmp.innerHTML=buildKanbanCard(t);
                    var newCard=tmp.firstChild;
                    colEl.appendChild(newCard);
                    if(addedIds.indexOf(t.id)!==-1){
                        newCard.classList.add('ticket-new-flash');
                        showToast('\uD83D\uDCCB New ticket assigned: '+t.name,'success');
                    }
                }
            });
            var incomingIds={};
            cols[state].forEach(function(t){incomingIds[String(t.id)]=true;});
            Object.keys(existingIds).forEach(function(tid){if(!incomingIds[tid])existingIds[tid].remove();});
        });

        updateCounts();
        applyFilters();
        bindDragDrop();
    }

    function loadTickets(){
        fetch('/customer_support/dashboard/tickets',{method:'GET',credentials:'same-origin',headers:{'Accept':'application/json'}})
        .then(function(r){if(!r.ok)throw new Error(r.status);return r.json();})
        .then(function(data){renderTickets(data.tickets||[]);})
        .catch(function(e){console.warn('Ticket refresh failed:',e);});
    }

    loadTickets();
    setInterval(loadTickets,20000);

    /* ── Drag and drop ── */
    var draggedCard=null;
    function bindDragDrop(){}

    document.addEventListener('dragstart',function(e){
        var card=e.target.closest('.kanban-card');
        if(!card)return;
        draggedCard=card;
        card.classList.add('dragging');
        e.dataTransfer.effectAllowed='move';
        e.dataTransfer.setData('text/plain',card.getAttribute('data-ticket-id'));
    });
    document.addEventListener('dragend',function(e){
        var card=e.target.closest('.kanban-card');
        if(card)card.classList.remove('dragging');
        document.querySelectorAll('.kanban-col').forEach(function(col){col.classList.remove('drag-over');});
        draggedCard=null;
    });
    document.querySelectorAll('.kanban-col').forEach(function(col){
        col.addEventListener('dragover',function(e){e.preventDefault();e.dataTransfer.dropEffect='move';this.classList.add('drag-over');});
        col.addEventListener('dragleave',function(e){if(!this.contains(e.relatedTarget))this.classList.remove('drag-over');});
        col.addEventListener('drop',function(e){
            e.preventDefault();this.classList.remove('drag-over');
            if(!draggedCard)return;
            var newState=this.getAttribute('data-state');
            var ticketId=draggedCard.getAttribute('data-ticket-id');
            var oldState=draggedCard.getAttribute('data-state');
            if(oldState===newState)return;
            this.querySelector('.kanban-cards').appendChild(draggedCard);
            draggedCard.setAttribute('data-state',newState);
            _renderedIds[ticketId]=true;
            updateCounts();
            saveTicketStatus(ticketId,newState);
        });
    });

    function saveTicketStatus(ticketId,newState){
        var fd=new FormData();
        fd.append('status',newState);
        var csrfToken=(window.odoo && window.odoo.csrf_token) ? window.odoo.csrf_token : '';
        if(csrfToken){fd.append('csrf_token',csrfToken);}
        fetch('/customer_support/ticket/'+ticketId+'/update_status',{method:'POST',body:fd,credentials:'same-origin',headers:{'Accept':'application/json'}})
        .then(function(r){return r.json();})
        .then(function(data){
            if(data.success)showToast('\u2713 Saved \u2014 '+newState.replace(/_/g,' '),'success');
            else showToast('\u2717 '+(data.error||'Save failed'),'error');
        })
        .catch(function(e){console.warn('Status update error:',e);showToast('\u2717 Network error','error');});
    }

    /* Kanban card click to open */
    document.addEventListener('click',function(e){
        var card=e.target.closest('.kanban-card');
        if(!card||card.classList.contains('dragging'))return;
        var id=card.getAttribute('data-ticket-id');
        if(id)window.location.href='/customer_support/ticket/'+id;
    });

    /* Hide tooltip on scroll */
    document.addEventListener('scroll',hideTooltip,true);

});
