// ── BACK BUTTON TRAP (focal dashboard) ───────────────────────────────────
document.addEventListener('DOMContentLoaded', function () {
    var modal     = document.getElementById('focalLogoutWarningModal');
    var stayBtn   = document.getElementById('focalModalStayBtn');
    var logoutBtn = document.getElementById('focalModalLogoutBtn');
    if (!modal) return;

    // Push 3 buffer entries so rapid back presses can't skip past the trap
    history.pushState({ focalTrap: true }, '', window.location.href);
    history.pushState({ focalTrap: true }, '', window.location.href);
    history.pushState({ focalTrap: true }, '', window.location.href);

    window.addEventListener('popstate', function () {
        // Re-arm immediately — push 3 entries to rebuild the buffer
        history.pushState({ focalTrap: true }, '', window.location.href);
        history.pushState({ focalTrap: true }, '', window.location.href);
        history.pushState({ focalTrap: true }, '', window.location.href);
        modal.classList.add('show');
    });

    // Re-arm after bfcache restore (use pushState, not reload, to keep trap alive)
    window.addEventListener('pageshow', function (e) {
        if (e.persisted) {
            history.pushState({ focalTrap: true }, '', window.location.href);
            history.pushState({ focalTrap: true }, '', window.location.href);
            history.pushState({ focalTrap: true }, '', window.location.href);
        }
    });

    stayBtn.addEventListener('click', function () { modal.classList.remove('show'); });
    logoutBtn.addEventListener('click', function () {
        window.location.replace('/customer_support/logout_manual');
    });

    // Make all dashboard logout links history-safe as well.
    document.addEventListener('click', function (e) {
        var logoutLink = e.target.closest('a[href="/customer_support/logout_manual"]');
        if (!logoutLink) return;
        e.preventDefault();
        window.location.replace('/customer_support/logout_manual');
    });
    // Click outside modal to dismiss
    modal.addEventListener('click', function (e) {
        if (e.target === modal) modal.classList.remove('show');
    });
});
